+    await expect(
+      resolveInboundMediaReference("media://inbound/nested%2Fa.png"),
+    ).rejects.toMatchObject({ code: "invalid-path" });
+    await expect(resolveInboundMediaReference("media://inbound/")).rejects.toMatchObject({
+      code: "invalid-path",
